fn scan_cancel_flags() -> &'static Mutex<HashMap<String, ScanCancelFlag>> {
    SCAN_CANCEL_FLAGS.get_or_init(|| Mutex::new(HashMap::new()))
}

fn scan_progress_registry() -> &'static Mutex<HashMap<String, ScanProgress>> {
    SCAN_PROGRESS.get_or_init(|| Mutex::new(HashMap::new()))
}

fn normalized_scan_run_id(
    run_id: Option<&str>,
) -> Result<Option<String>, Box<dyn std::error::Error>> {
    match run_id {
        Some(value) if value.trim().is_empty() => {
            Err("scan run_id requires a non-empty value".into())
        }
        Some(value) => Ok(Some(value.trim().to_string())),
        None => Ok(None),
    }
}

fn register_scan_run(
    run_id: Option<&str>,
) -> Result<Option<ScanCancelFlag>, Box<dyn std::error::Error>> {
    let Some(run_id) = run_id else {
        return Ok(None);
    };
    let flag = Arc::new(AtomicBool::new(false));
    let mut flags = scan_cancel_flags()
        .lock()
        .map_err(|_| "scan cancellation registry is unavailable")?;
    if flags.contains_key(run_id) {
        return Err(format!("scan run_id is already active: {run_id}").into());
    }
    flags.insert(run_id.to_string(), flag.clone());
    Ok(Some(flag))
}

fn inactive_scan_progress(run_id: String) -> ScanProgress {
    ScanProgress {
        run_id,
        active: false,
        canceled: false,
        source_id: None,
        source_label: None,
        source_index: 0,
        source_count: 0,
        files_seen: 0,
        source_files_seen: 0,
        source_files_discovered: 0,
        source_file_count: None,
        prompts_found: 0,
        limit: None,
        updated_at: Utc::now().to_rfc3339(),
    }
}

fn start_scan_progress(run_id: Option<&str>, source_count: usize, limit: usize) {
    let Some(run_id) = run_id else {
        return;
    };
    if let Ok(mut progress) = scan_progress_registry().lock() {
        progress.insert(
            run_id.to_string(),
            ScanProgress {
                run_id: run_id.to_string(),
                active: true,
                canceled: false,
                source_id: None,
                source_label: None,
                source_index: 0,
                source_count,
                files_seen: 0,
                source_files_seen: 0,
                source_files_discovered: 0,
                source_file_count: None,
                prompts_found: 0,
                limit: if limit == usize::MAX {
                    None
                } else {
                    Some(limit)
                },
                updated_at: Utc::now().to_rfc3339(),
            },
        );
    }
}

fn update_scan_progress<F>(run_id: Option<&str>, update: F)
where
    F: FnOnce(&mut ScanProgress),
{
    let Some(run_id) = run_id else {
        return;
    };
    if let Ok(mut progress) = scan_progress_registry().lock() {
        if let Some(progress) = progress.get_mut(run_id) {
            update(progress);
            progress.updated_at = Utc::now().to_rfc3339();
        }
    }
}

fn remove_scan_progress(run_id: &str) {
    if let Ok(mut progress) = scan_progress_registry().lock() {
        progress.remove(run_id);
    }
}

fn scan_cancel_requested(cancel_flag: Option<&ScanCancelFlag>) -> bool {
    cancel_flag
        .map(|flag| flag.load(Ordering::Relaxed))
        .unwrap_or(false)
}

fn push_scan_canceled_warning(warnings: &mut Vec<String>) {
    if !warnings
        .iter()
        .any(|warning| warning == SCAN_CANCELED_WARNING)
    {
        warnings.push(SCAN_CANCELED_WARNING.to_string());
    }
}

fn scan_was_canceled(warnings: &[String]) -> bool {
    warnings
        .iter()
        .any(|warning| warning == SCAN_CANCELED_WARNING)
}

fn should_persist_scan_result(persist: bool, persist_on_cancel: bool, warnings: &[String]) -> bool {
    persist && (persist_on_cancel || !scan_was_canceled(warnings))
}

pub fn run_scan(options: ScanOptions) -> Result<ScanResult, Box<dyn std::error::Error>> {
    let run_id = normalized_scan_run_id(options.run_id.as_deref())?;
    let cancel_flag = register_scan_run(run_id.as_deref())?;
    let result = run_scan_with_cancel(options, cancel_flag.as_ref());
    if let Some(run_id) = run_id {
        scan_cancel_flags()
            .lock()
            .map_err(|_| "scan cancellation registry is unavailable")?
            .remove(&run_id);
        remove_scan_progress(&run_id);
    }
    result
}

pub fn cancel_scan_run(
    options: CancelScanOptions,
) -> Result<CancelScanResult, Box<dyn std::error::Error>> {
    let run_id = normalized_scan_run_id(Some(options.run_id.as_str()))?
        .ok_or("scan run_id requires a non-empty value")?;
    let canceled = scan_cancel_flags()
        .lock()
        .map_err(|_| "scan cancellation registry is unavailable")?
        .get(&run_id)
        .map(|flag| {
            flag.store(true, Ordering::Relaxed);
            update_scan_progress(Some(&run_id), |progress| {
                progress.canceled = true;
            });
            true
        })
        .unwrap_or(false);
    Ok(CancelScanResult { run_id, canceled })
}

pub fn scan_progress_run(
    options: ScanProgressOptions,
) -> Result<ScanProgress, Box<dyn std::error::Error>> {
    let run_id = normalized_scan_run_id(Some(options.run_id.as_str()))?
        .ok_or("scan run_id requires a non-empty value")?;
    let progress = scan_progress_registry()
        .lock()
        .map_err(|_| "scan progress registry is unavailable")?
        .get(&run_id)
        .cloned()
        .unwrap_or_else(|| inactive_scan_progress(run_id));
    Ok(progress)
}

fn run_scan_with_cancel(
    options: ScanOptions,
    cancel_flag: Option<&ScanCancelFlag>,
) -> Result<ScanResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("scan limit requires a positive integer".into());
    }
    if matches!(options.source_limit, Some(0)) {
        return Err("scan source limit requires a positive integer".into());
    }
    let limit = options.limit.unwrap_or(usize::MAX);
    let source_limit = options.source_limit.unwrap_or(usize::MAX);
    let preview_limit = options.preview_limit;
    let include_markdown = options.include_markdown.unwrap_or(true);
    let write_markdown = options.write_markdown.unwrap_or(true);
    let persist = options.persist.unwrap_or(true);
    let persist_on_cancel = options.persist_on_cancel.unwrap_or(true);
    if matches!(options.output_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err("output path requires a non-empty value".into());
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err("database path requires a non-empty value".into());
    }
    if !write_markdown && options.output_path.is_some() {
        return Err("output path cannot be used when markdown export is disabled".into());
    }
    let mut warnings = Vec::new();
    let preview_sort = PreviewSort::from_option(options.preview_sort.as_deref())?;
    validate_source_ids(options.source_ids.as_deref())?;
    let mut prompts = Vec::new();
    let mut summaries = Vec::new();
    let sources = selected_source_specs(options.source_ids.as_deref());
    let source_count = sources.len();
    let run_id = normalized_scan_run_id(options.run_id.as_deref())?;
    start_scan_progress(run_id.as_deref(), source_count, limit);

    for (source_index, source) in sources.into_iter().enumerate() {
        if scan_cancel_requested(cancel_flag) {
            update_scan_progress(run_id.as_deref(), |progress| {
                progress.canceled = true;
            });
            push_scan_canceled_warning(&mut warnings);
            break;
        }
        update_scan_progress(run_id.as_deref(), |progress| {
            progress.source_id = Some(source.id.to_string());
            progress.source_label = Some(source.label.to_string());
            progress.source_index = source_index + 1;
            progress.source_count = source_count;
            progress.source_files_seen = 0;
            progress.source_files_discovered = 0;
            progress.source_file_count = None;
        });
        let mut summary = SourceSummary {
            id: source.id.to_string(),
            label: source.label.to_string(),
            root_path: source.root.display().to_string(),
            files_seen: 0,
            prompts_found: 0,
            average_quality: 0.0,
            weak_prompt_count: 0,
            status: "missing".to_string(),
            notes: Vec::new(),
        };

        if !source.root.exists() {
            summary.notes.push("이 머신에 경로가 없습니다.".to_string());
            summaries.push(summary);
            continue;
        }

        summary.status = "ok".to_string();
        match collect_from_source(
            &source,
            &mut summary,
            limit.saturating_sub(prompts.len()).min(source_limit),
            cancel_flag,
            run_id.as_deref(),
            prompts.len(),
        ) {
            Ok(mut found) => {
                summary.prompts_found = found.len();
                summarize_source_quality(&mut summary, &found);
                promote_source_notes_to_warning(&source, &mut summary, &mut warnings);
                prompts.append(&mut found);
            }
            Err(err) => {
                summary.status = "partial".to_string();
                summary.notes.push(err.to_string());
                warnings.push(format!("{}: {}", source.label, err));
            }
        }
        if scan_cancel_requested(cancel_flag) {
            summary.status = "partial".to_string();
            summary
                .notes
                .push("현재 파일 처리 후 스캔을 취소했습니다.".to_string());
            update_scan_progress(run_id.as_deref(), |progress| {
                progress.canceled = true;
            });
            push_scan_canceled_warning(&mut warnings);
            summaries.push(summary);
            break;
        }
        summaries.push(summary);

        if limit != usize::MAX && prompts.len() >= limit {
            warnings.push(format!(
                "설정된 제한 {limit}개 프롬프트에서 스캔을 중지했습니다."
            ));
            break;
        }
    }

    prompts.sort_by(|a, b| {
        let at = a.timestamp.as_deref().unwrap_or("");
        let bt = b.timestamp.as_deref().unwrap_or("");
        at.cmp(bt).then_with(|| a.source.cmp(&b.source))
    });
    prompts.dedup_by(|a, b| a.hash == b.hash && a.source == b.source);

    let stats = build_stats(&prompts, summaries);
    let generated_at = Utc::now().to_rfc3339();
    let should_render_markdown = write_markdown || include_markdown;
    let markdown = if should_render_markdown {
        render_markdown(&generated_at, &stats, &prompts, &warnings)
    } else {
        String::new()
    };
    let requested_output_path = options.output_path.map(PathBuf::from);
    let output_path = if write_markdown {
        Some(requested_output_path.unwrap_or_else(default_markdown_path))
    } else {
        None
    };

    if let Some(path) = &output_path {
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent)?;
        }
        fs::write(path, &markdown)?;
    }

    let should_persist = should_persist_scan_result(persist, persist_on_cancel, &warnings);
    if persist && !should_persist {
        warnings.push(SCAN_CANCELED_NOT_PERSISTED_WARNING.to_string());
    }

    let persistence = if should_persist {
        let database_path = options
            .database_path
            .as_deref()
            .map(PathBuf::from)
            .unwrap_or_else(default_database_path);
        Some(persist_scan_result(
            &database_path,
            &generated_at,
            &prompts,
            &stats,
            &warnings,
        )?)
    } else {
        None
    };

    let response_prompts = response_prompts(&prompts, preview_limit, preview_sort);
    let returned_prompt_count = response_prompts.len();
    let prompts_truncated = returned_prompt_count < prompts.len();
    let response_markdown = if include_markdown {
        markdown
    } else {
        String::new()
    };

    Ok(ScanResult {
        generated_at,
        output_path: output_path.map(|path| path.display().to_string()),
        markdown: response_markdown,
        stats,
        prompts: response_prompts,
        returned_prompt_count,
        prompts_truncated,
        preview_sort: preview_sort.as_str().to_string(),
        markdown_included: include_markdown,
        markdown_written: write_markdown,
        persistence,
        warnings,
    })
}

pub fn build_scan_plan(options: ScanPlanOptions) -> Result<ScanPlan, Box<dyn std::error::Error>> {
    validate_source_ids(options.source_ids.as_deref())?;
    let generated_at = Utc::now().to_rfc3339();
    let sources = selected_source_specs(options.source_ids.as_deref());
    Ok(build_scan_plan_for_sources(generated_at, sources))
}

pub fn run_project_work_report(
    options: ProjectWorkReportOptions,
) -> Result<ProjectWorkReport, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("work-report limit requires a positive integer".into());
    }
    if matches!(options.session_limit, Some(0)) {
        return Err("work-report session_limit requires a positive integer".into());
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err("work-report database path requires a non-empty value".into());
    }
    let source = source_specs()
        .into_iter()
        .find(|source| source.id == "project-progress-logs")
        .ok_or("project progress log source is unavailable")?;
    let mut report = build_project_progress_work_report(&source, options.limit)?;
    let session_limit = options
        .session_limit
        .unwrap_or(DEFAULT_PROJECT_WORK_SESSION_LIMIT);
    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let refresh_index = options.refresh_session_index.unwrap_or(false);
    let evidence = project_work_session_evidence(
        &database_path,
        session_limit,
        refresh_index,
        &mut report.warnings,
    )?;
    let sessions = evidence.prompts;
    report.session_evidence_index_used = evidence.index_used;
    report.session_evidence_index_updated = evidence.index_updated;
    report.session_evidence_index_count = evidence.index_count;
    report.session_scan_prompt_count = sessions.len();
    report.session_scan_sources = prompt_source_counts(&sessions);
    attach_session_evidence(&mut report.items, &sessions);
    refresh_project_work_session_summary(&mut report);
    if report.session_scan_prompt_count > 0 && report.session_evidence_count == 0 {
        report.warnings.push(
            "Session evidence: scanned raw session prompts, but none matched the selected project/date work items.".to_string(),
        );
    }
    Ok(report)
}

pub fn run_project_work_status_export(
    options: ProjectWorkStatusExportOptions,
) -> Result<ProjectWorkStatusExportResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("work-status-export limit requires a positive integer".into());
    }
    if matches!(options.session_limit, Some(0)) {
        return Err("work-status-export session_limit requires a positive integer".into());
    }
    if options.full_session_index.unwrap_or(false) && options.session_limit.is_some() {
        return Err(
            "work-status-export full_session_index cannot be combined with session_limit".into(),
        );
    }
    let row_filter =
        normalize_project_work_status_export_row_filter(options.row_filter.as_deref())?;
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err("work-status-export database path requires a non-empty value".into());
    }

    let requested_limit = options
        .limit
        .unwrap_or(DEFAULT_PROJECT_WORK_STATUS_EXPORT_LIMIT);
    let limit = requested_limit.min(MAX_PROJECT_WORK_STATUS_EXPORT_LIMIT);
    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let full_session_index = options.full_session_index.unwrap_or(false);
    let stored_session_index_count = project_work_session_index_total_count(&database_path)?;
    let session_limit = if full_session_index && stored_session_index_count > 0 {
        Some(stored_session_index_count)
    } else {
        options.session_limit
    };
    let report = run_project_work_report(ProjectWorkReportOptions {
        limit: None,
        session_limit,
        database_path: Some(database_path.display().to_string()),
        refresh_session_index: options.refresh_session_index,
    })?;
    let session_evidence_index_total_count =
        project_work_session_index_total_count(&database_path)?;
    let mut warnings = report.warnings.clone();
    if requested_limit > MAX_PROJECT_WORK_STATUS_EXPORT_LIMIT {
        warnings.push(format!(
            "work-status-export limit capped at {MAX_PROJECT_WORK_STATUS_EXPORT_LIMIT}"
        ));
    }
    if full_session_index && stored_session_index_count == 0 {
        warnings.push(
            "work-status-export full_session_index requested but no stored session index exists; used the default session scan limit. Run work-session-index first for full stored verification."
                .to_string(),
        );
    }

    let all_rows = {
        let mut rows =
            build_project_work_status_export_rows(&report, session_evidence_index_total_count);
        annotate_project_work_status_export_row_date_hints(&database_path, &mut rows)?;
        filter_project_work_status_export_rows(rows, row_filter)
    };
    let (rows, total_row_count, row_offset, rows_truncated, next_row_offset) =
        paginate_project_work_status_export_rows(all_rows, limit, options.offset.unwrap_or(0));
    let markdown = render_project_work_status_export_markdown(
        &report,
        &rows,
        &warnings,
        row_offset,
        total_row_count,
        session_evidence_index_total_count,
    );

    Ok(ProjectWorkStatusExportResult {
        generated_at: report.generated_at.clone(),
        database_path: database_path.display().to_string(),
        markdown,
        total_row_count,
        row_offset,
        returned_row_count: rows.len(),
        next_row_offset,
        rows_truncated,
        report_total_items: report.total_items,
        report_project_count: report.project_count,
        report_date_count: report.date_count,
        report_files_seen: report.files_seen,
        report_session_scan_prompt_count: report.session_scan_prompt_count,
        report_session_evidence_count: report.session_evidence_count,
        report_unique_session_evidence_count: report.session_evidence_unique_count,
        report_session_evidence_index_used: report.session_evidence_index_used,
        report_session_evidence_index_updated: report.session_evidence_index_updated,
        report_session_evidence_index_count: report.session_evidence_index_count,
        report_session_evidence_index_total_count: session_evidence_index_total_count,
        report_session_evidence_mode: report.session_evidence_mode.clone(),
        rows,
        warnings,
    })
}

fn project_work_session_index_effective_max_batches(
    until_complete: bool,
    max_batches: Option<usize>,
) -> Option<usize> {
    if until_complete {
        Some(max_batches.unwrap_or(DEFAULT_PROJECT_WORK_SESSION_INDEX_UNTIL_COMPLETE_MAX_BATCHES))
    } else {
        max_batches
    }
}

fn project_work_session_index_needs_long_run_confirmation(max_batches: Option<usize>) -> bool {
    max_batches.is_some_and(|max_batches| {
        max_batches > CONFIRMATION_FREE_PROJECT_WORK_SESSION_INDEX_MAX_BATCHES
    })
}

pub fn run_project_work_session_evidence_candidates(
    options: ProjectWorkSessionEvidenceCandidatesOptions,
) -> Result<ProjectWorkSessionEvidenceCandidatesResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("work-session-evidence-candidates limit requires a positive integer".into());
    }
    if matches!(options.session_limit, Some(0)) {
        return Err(
            "work-session-evidence-candidates session_limit requires a positive integer".into(),
        );
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err(
            "work-session-evidence-candidates database path requires a non-empty value".into(),
        );
    }
    let row_filter = normalize_project_work_row_filter(
        options.row_filter.as_deref(),
        "work-session-evidence-candidates",
    )?;

    let requested_limit = options
        .limit
        .unwrap_or(DEFAULT_PROJECT_WORK_SESSION_EVIDENCE_CANDIDATE_LIMIT);
    let limit = requested_limit.min(MAX_PROJECT_WORK_SESSION_EVIDENCE_CANDIDATE_LIMIT);
    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let stored_session_index_count = project_work_session_index_total_count(&database_path)?;
    let session_limit = options
        .session_limit
        .unwrap_or_else(|| stored_session_index_count.max(DEFAULT_PROJECT_WORK_SESSION_LIMIT));
    let report = run_project_work_report(ProjectWorkReportOptions {
        limit: None,
        session_limit: Some(session_limit),
        database_path: Some(database_path.display().to_string()),
        refresh_session_index: options.refresh_session_index,
    })?;
    let session_evidence_index_total_count =
        project_work_session_index_total_count(&database_path)?;
    let all_rows =
        build_project_work_status_export_rows(&report, session_evidence_index_total_count);
    let total_row_count = all_rows.len();
    let bounded_session_limit_count = all_rows
        .iter()
        .filter(|row| row.session_evidence_audit == "bounded-session-limit")
        .count();
    let unresolved_after_full_index_count = all_rows
        .iter()
        .filter(|row| row.session_evidence_audit == "unresolved-after-full-index")
        .count();
    let needs_title_normalization_count = all_rows
        .iter()
        .filter(|row| row.needs_title_normalization)
        .count();
    let mut warnings = report.warnings.clone();
    if requested_limit > MAX_PROJECT_WORK_SESSION_EVIDENCE_CANDIDATE_LIMIT {
        warnings.push(format!(
            "work-session-evidence-candidates limit capped at {MAX_PROJECT_WORK_SESSION_EVIDENCE_CANDIDATE_LIMIT}"
        ));
    }
    if bounded_session_limit_count > 0 {
        warnings.push(format!(
            "Session evidence candidates use a bounded session index for {bounded_session_limit_count} project/day rows; increase session_limit or refresh the session index before treating them as full-index unresolved."
        ));
    }
    let mut candidates = build_project_work_session_evidence_candidates_from_rows(
        &all_rows,
        usize::MAX,
        options.needs_title_normalization,
    );
    annotate_project_work_session_evidence_candidate_date_hints(&database_path, &mut candidates)?;
    let mut candidates = filter_project_work_session_evidence_candidates(candidates, row_filter);
    sort_project_work_session_evidence_candidates_for_review(&mut candidates);
    let total_candidate_count = candidates.len();
    candidates.truncate(limit);

    Ok(ProjectWorkSessionEvidenceCandidatesResult {
        generated_at: report.generated_at.clone(),
        database_path: database_path.display().to_string(),
        requested_limit,
        session_limit_used: session_limit,
        total_candidate_count,
        returned_candidate_count: candidates.len(),
        report_total_rows: total_row_count,
        report_total_items: report.total_items,
        report_project_count: report.project_count,
        report_date_count: report.date_count,
        report_files_seen: report.files_seen,
        report_session_scan_prompt_count: report.session_scan_prompt_count,
        report_session_evidence_count: report.session_evidence_count,
        report_unique_session_evidence_count: report.session_evidence_unique_count,
        report_session_evidence_index_used: report.session_evidence_index_used,
        report_session_evidence_index_updated: report.session_evidence_index_updated,
        report_session_evidence_index_count: report.session_evidence_index_count,
        report_session_evidence_index_total_count: session_evidence_index_total_count,
        report_session_evidence_mode: report.session_evidence_mode,
        bounded_session_limit_count,
        unresolved_after_full_index_count,
        needs_title_normalization_count,
        candidates,
        warnings,
    })
}

pub async fn run_project_work_session_evidence_proposals(
    options: ProjectWorkSessionEvidenceProposalsOptions,
) -> Result<ProjectWorkSessionEvidenceProposalsResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("work-session-evidence-proposals limit requires a positive integer".into());
    }
    if matches!(options.session_limit, Some(0)) {
        return Err(
            "work-session-evidence-proposals session_limit requires a positive integer".into(),
        );
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err(
            "work-session-evidence-proposals database path requires a non-empty value".into(),
        );
    }
    normalize_project_work_row_filter(
        options.row_filter.as_deref(),
        "work-session-evidence-proposals",
    )?;

    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let limit = options
        .limit
        .unwrap_or(DEFAULT_PROJECT_WORK_SESSION_EVIDENCE_PROPOSAL_LIMIT)
        .min(MAX_PROJECT_WORK_SESSION_EVIDENCE_PROPOSAL_LIMIT);
    let candidates = run_project_work_session_evidence_candidates(
        ProjectWorkSessionEvidenceCandidatesOptions {
            database_path: Some(database_path.display().to_string()),
            limit: Some(limit),
            row_filter: options.row_filter,
            session_limit: options.session_limit,
            refresh_session_index: options.refresh_session_index,
            needs_title_normalization: options.needs_title_normalization,
        },
    )?;
    let mut result = project_work_session_evidence_proposals_with_env(
        candidates,
        !options.ai.unwrap_or(false),
        load_improve_env(),
    )
    .await?;
    result.generated_at = Utc::now().to_rfc3339();
    result.database_path = database_path.display().to_string();
    Ok(result)
}

pub fn run_project_work_session_evidence_review_queue(
    options: ProjectWorkSessionEvidenceReviewQueueOptions,
) -> Result<ProjectWorkSessionEvidenceReviewQueueResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("work-session-evidence-review-queue limit requires a positive integer".into());
    }
    if matches!(options.session_limit, Some(0)) {
        return Err(
            "work-session-evidence-review-queue session_limit requires a positive integer".into(),
        );
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err(
            "work-session-evidence-review-queue database path requires a non-empty value".into(),
        );
    }

    let generated_at = Utc::now().to_rfc3339();
    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let limit = options
        .limit
        .unwrap_or(DEFAULT_PROJECT_WORK_SESSION_EVIDENCE_REVIEW_QUEUE_LIMIT)
        .min(MAX_PROJECT_WORK_SESSION_EVIDENCE_REVIEW_QUEUE_LIMIT);
    let mut conn = open_promptvault_database(&database_path)?;
    let mut synced_candidate_count = 0usize;
    let mut stale_candidate_count = 0usize;
    let mut warnings = Vec::new();

    if options.sync_candidates.unwrap_or(false) {
        let candidates = run_project_work_session_evidence_candidates(
            ProjectWorkSessionEvidenceCandidatesOptions {
                database_path: Some(database_path.display().to_string()),
                limit: Some(MAX_PROJECT_WORK_SESSION_EVIDENCE_CANDIDATE_LIMIT),
                row_filter: None,
                session_limit: options.session_limit,
                refresh_session_index: options.refresh_session_index,
                needs_title_normalization: None,
            },
        )?;
        if candidates.returned_candidate_count < candidates.total_candidate_count {
            warnings.push(format!(
                "Only {} of {} session evidence candidates were synced; stale marking was skipped for this run.",
                candidates.returned_candidate_count, candidates.total_candidate_count
            ));
        }
        synced_candidate_count = candidates.candidates.len();
        stale_candidate_count =
            sync_project_work_session_evidence_review_queue(&mut conn, &candidates, &generated_at)?;
        warnings.extend(candidates.warnings);
    }

    let rows = read_project_work_session_evidence_review_queue(&conn, limit)?;
    Ok(ProjectWorkSessionEvidenceReviewQueueResult {
        generated_at,
        database_path: database_path.display().to_string(),
        synced_candidate_count,
        stale_candidate_count,
        total_items: rows.total_items,
        returned_item_count: rows.items.len(),
        pending_review_count: rows.pending_review_count,
        stale_count: rows.stale_count,
        approved_count: rows.approved_count,
        rejected_count: rows.rejected_count,
        needs_title_normalization_count: rows.needs_title_normalization_count,
        items: rows.items,
        warnings,
    })
}

pub fn run_project_work_session_evidence_review_queue_update(
    options: ProjectWorkSessionEvidenceReviewQueueUpdateOptions,
) -> Result<ProjectWorkSessionEvidenceReviewQueueResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("work-session-evidence-review-queue limit requires a positive integer".into());
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err(
            "work-session-evidence-review-queue database path requires a non-empty value".into(),
        );
    }
    let candidate_id = options.candidate_id.trim();
    if candidate_id.is_empty() {
        return Err(
            "work-session-evidence-review-queue candidate id requires a non-empty value".into(),
        );
    }
    let (review_state, default_reason) =
        normalized_project_work_session_evidence_review_queue_update_state(&options.review_state)?;
    let review_reason = normalized_optional_filter(
        options.review_reason.as_deref(),
        "work-session-evidence-review-queue reason requires a non-empty value",
    )?
    .unwrap_or_else(|| default_reason.to_string());

    let generated_at = Utc::now().to_rfc3339();
    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let limit = options
        .limit
        .unwrap_or(DEFAULT_PROJECT_WORK_SESSION_EVIDENCE_REVIEW_QUEUE_LIMIT)
        .min(MAX_PROJECT_WORK_SESSION_EVIDENCE_REVIEW_QUEUE_LIMIT);
    let conn = open_promptvault_database(&database_path)?;
    update_project_work_session_evidence_review_queue_state(
        &conn,
        candidate_id,
        review_state,
        &review_reason,
        options.source_review.as_ref(),
        &generated_at,
    )?;
    let rows = read_project_work_session_evidence_review_queue(&conn, limit)?;
    Ok(ProjectWorkSessionEvidenceReviewQueueResult {
        generated_at,
        database_path: database_path.display().to_string(),
        synced_candidate_count: 0,
        stale_candidate_count: 0,
        total_items: rows.total_items,
        returned_item_count: rows.items.len(),
        pending_review_count: rows.pending_review_count,
        stale_count: rows.stale_count,
        approved_count: rows.approved_count,
        rejected_count: rows.rejected_count,
        needs_title_normalization_count: rows.needs_title_normalization_count,
        items: rows.items,
        warnings: Vec::new(),
    })
}

pub fn run_project_work_session_evidence_review_apply(
    options: ProjectWorkSessionEvidenceReviewApplyOptions,
) -> Result<ProjectWorkSessionEvidenceReviewApplyResult, Box<dyn std::error::Error>> {
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err(
            "work-session-evidence-review-apply database path requires a non-empty value".into(),
        );
    }
    if matches!(options.limit, Some(0)) {
        return Err("work-session-evidence-review-apply limit requires a positive integer".into());
    }
    let generated_at = Utc::now().to_rfc3339();
    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let limit = options
        .limit
        .unwrap_or(DEFAULT_PROJECT_WORK_SESSION_EVIDENCE_REVIEWED_ITEM_LIMIT)
        .min(MAX_PROJECT_WORK_SESSION_EVIDENCE_REVIEWED_ITEM_LIMIT);
    let mut conn = open_promptvault_database(&database_path)?;
    let approved_queue_count =
        count_project_work_session_evidence_review_queue_state(&conn, "approved")?;
    let approved_rows =
        read_project_work_session_evidence_review_queue_items_by_state(&conn, "approved", limit)?;
    let processed_queue_count = approved_rows.len();
    let applied_item_count = persist_project_work_session_evidence_reviewed_items(
        &mut conn,
        &approved_rows,
        &generated_at,
    )?;
    let skipped_existing_count = processed_queue_count.saturating_sub(applied_item_count);
    let reviewed_rows =
        read_project_work_session_evidence_reviewed_items(&conn, limit, None, None)?;
    let mut warnings = Vec::new();
    if approved_queue_count == 0 {
        warnings.push(
            "승인된 세션근거 검토 row가 없어 durable reviewed row를 저장하지 않았습니다."
                .to_string(),
        );
    } else if processed_queue_count < approved_queue_count {
        warnings.push(format!(
            "승인된 세션근거 검토 row {approved_queue_count}개 중 {processed_queue_count}개만 이번 실행에서 처리했습니다."
        ));
    }
    Ok(ProjectWorkSessionEvidenceReviewApplyResult {
        generated_at,
        database_path: database_path.display().to_string(),
        approved_queue_count,
        processed_queue_count,
        applied_item_count,
        skipped_existing_count,
        total_reviewed_item_count: reviewed_rows.total_items,
        returned_item_count: reviewed_rows.items.len(),
        items: reviewed_rows.items,
        warnings,
    })
}

