pub fn run_project_work_session_evidence_nearby(
    options: ProjectWorkSessionEvidenceNearbyOptions,
) -> Result<ProjectWorkSessionEvidenceNearbyResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("work-session-evidence-nearby limit requires a positive integer".into());
    }
    let project = options.project.trim();
    if project.is_empty() {
        return Err("work-session-evidence-nearby project requires a non-empty value".into());
    }
    let date = options.date.trim();
    if date.is_empty() {
        return Err("work-session-evidence-nearby date requires a non-empty value".into());
    }
    if NaiveDate::parse_from_str(date, "%Y-%m-%d").is_err() {
        return Err("work-session-evidence-nearby date requires YYYY-MM-DD".into());
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err("work-session-evidence-nearby database path requires a non-empty value".into());
    }
    let query = normalized_optional_filter(
        options.query.as_deref(),
        "work-session-evidence-nearby query requires a non-empty value",
    )?;
    let query_terms = project_work_session_evidence_nearby_query_terms(query.as_deref());

    let requested_limit = options
        .limit
        .unwrap_or(DEFAULT_PROJECT_WORK_SESSION_EVIDENCE_NEARBY_LIMIT);
    let limit = requested_limit.min(MAX_PROJECT_WORK_SESSION_EVIDENCE_NEARBY_LIMIT);
    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let conn = open_promptvault_database(&database_path)?;
    let read_limit = if query_terms.is_empty() {
        limit
    } else {
        MAX_PROJECT_WORK_SESSION_EVIDENCE_NEARBY_LIMIT
    };
    let mut items = read_project_work_session_evidence_nearby_items(
        &conn,
        project,
        date,
        read_limit,
        &query_terms,
    )?;
    if !query_terms.is_empty() {
        sort_project_work_session_evidence_nearby_items_for_query(&mut items);
        items.truncate(limit);
    }
    let total_match_count = count_project_work_session_evidence_for_project(&conn, project)?;
    let mut warnings = vec![
        "Nearby same-project sessions are navigation hints only; they do not create or approve session evidence.".to_string(),
    ];
    if query.is_some() && query_terms.is_empty() {
        warnings.push(
            "Nearby query did not contain searchable terms after redaction and stop-word filtering."
                .to_string(),
        );
    }
    if requested_limit > MAX_PROJECT_WORK_SESSION_EVIDENCE_NEARBY_LIMIT {
        warnings.push(format!(
            "work-session-evidence-nearby limit capped at {MAX_PROJECT_WORK_SESSION_EVIDENCE_NEARBY_LIMIT}"
        ));
    }
    if total_match_count == 0 {
        warnings.push(
            "No same-project session evidence records were found in the current session index."
                .to_string(),
        );
    }
    Ok(ProjectWorkSessionEvidenceNearbyResult {
        generated_at: Utc::now().to_rfc3339(),
        database_path: database_path.display().to_string(),
        project: project.to_string(),
        date: date.to_string(),
        query,
        query_term_count: query_terms.len(),
        requested_limit,
        total_match_count,
        returned_item_count: items.len(),
        items,
        warnings,
    })
}

pub fn run_project_work_session_evidence_source_search(
    options: ProjectWorkSessionEvidenceSourceSearchOptions,
) -> Result<ProjectWorkSessionEvidenceSourceSearchResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("work-session-evidence-source-search limit requires a positive integer".into());
    }
    if matches!(options.max_lines, Some(0)) {
        return Err(
            "work-session-evidence-source-search max-lines requires a positive integer".into(),
        );
    }
    let source_path = options.source_path.trim();
    if source_path.is_empty() {
        return Err(
            "work-session-evidence-source-search source-path requires a non-empty value".into(),
        );
    }
    let query = options.query.trim();
    if query.is_empty() {
        return Err("work-session-evidence-source-search query requires a non-empty value".into());
    }
    let requested_limit = options
        .limit
        .unwrap_or(DEFAULT_PROJECT_WORK_SESSION_EVIDENCE_SOURCE_SEARCH_LIMIT);
    let limit = requested_limit.min(MAX_PROJECT_WORK_SESSION_EVIDENCE_SOURCE_SEARCH_LIMIT);
    let requested_max_lines = options
        .max_lines
        .unwrap_or(DEFAULT_PROJECT_WORK_SESSION_EVIDENCE_SOURCE_SEARCH_MAX_LINES);
    let max_lines =
        requested_max_lines.min(MAX_PROJECT_WORK_SESSION_EVIDENCE_SOURCE_SEARCH_MAX_LINES);
    let path = PathBuf::from(source_path);
    let canonical_path = path.canonicalize().map_err(|err| {
        format!("work-session-evidence-source-search source-path is not readable: {err}")
    })?;
    if !canonical_path.is_file() {
        return Err("work-session-evidence-source-search source-path must be a file".into());
    }
    let source_kind = project_work_session_evidence_source_search_path_kind(&canonical_path)
        .ok_or(
        "work-session-evidence-source-search source-path must be under a known session source root",
    )?;
    if !project_work_session_evidence_source_search_kind_supported(source_kind) {
        return Err(
            "work-session-evidence-source-search currently supports JSONL session files and Antigravity SQLite conversation DB files only"
                .into(),
        );
    }

    let query_terms = project_work_session_evidence_nearby_query_terms(Some(query));
    let mut warnings = vec![
        "Raw source search is read-only and redacted; returned snippets do not create or approve session evidence."
            .to_string(),
    ];
    if requested_limit > MAX_PROJECT_WORK_SESSION_EVIDENCE_SOURCE_SEARCH_LIMIT {
        warnings.push(format!(
            "work-session-evidence-source-search limit capped at {MAX_PROJECT_WORK_SESSION_EVIDENCE_SOURCE_SEARCH_LIMIT}"
        ));
    }
    if requested_max_lines > MAX_PROJECT_WORK_SESSION_EVIDENCE_SOURCE_SEARCH_MAX_LINES {
        warnings.push(format!(
            "work-session-evidence-source-search max-lines capped at {MAX_PROJECT_WORK_SESSION_EVIDENCE_SOURCE_SEARCH_MAX_LINES}"
        ));
    }
    let mut scanned_line_count = 0;
    let mut matched_line_count = 0;
    let mut items = Vec::new();
    if query_terms.is_empty() {
        warnings.push(
            "Source search query did not contain searchable terms after redaction and stop-word filtering."
                .to_string(),
        );
    } else {
        let search = read_project_work_session_evidence_source_search_items(
            &canonical_path,
            source_kind,
            &query_terms,
            limit,
            max_lines,
        )?;
        scanned_line_count = search.scanned_line_count;
        matched_line_count = search.matched_line_count;
        items = search.items;
        if search.hit_max_lines {
            warnings.push(format!(
                "Source search stopped after {max_lines} source rows/lines; increase --max-lines for a wider bounded search."
            ));
        }
    }

    Ok(ProjectWorkSessionEvidenceSourceSearchResult {
        generated_at: Utc::now().to_rfc3339(),
        source_path: canonical_path.display().to_string(),
        query: query.to_string(),
        query_term_count: query_terms.len(),
        requested_limit,
        requested_max_lines,
        scanned_line_count,
        matched_line_count,
        returned_item_count: items.len(),
        items,
        warnings,
    })
}

pub fn run_project_work_session_evidence_source_proposals(
    options: ProjectWorkSessionEvidenceSourceProposalsOptions,
) -> Result<ProjectWorkSessionEvidenceSourceProposalsResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err(
            "work-session-evidence-source-proposals limit requires a positive integer".into(),
        );
    }
    if matches!(options.max_lines, Some(0)) {
        return Err(
            "work-session-evidence-source-proposals max-lines requires a positive integer".into(),
        );
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err(
            "work-session-evidence-source-proposals database path requires a non-empty value"
                .into(),
        );
    }
    let candidate_id = options.candidate_id.trim();
    if candidate_id.is_empty() {
        return Err(
            "work-session-evidence-source-proposals candidate-id requires a non-empty value".into(),
        );
    }

    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let candidates = run_project_work_session_evidence_candidates(
        ProjectWorkSessionEvidenceCandidatesOptions {
            database_path: Some(database_path.display().to_string()),
            limit: Some(MAX_PROJECT_WORK_SESSION_EVIDENCE_CANDIDATE_LIMIT),
            row_filter: None,
            session_limit: None,
            refresh_session_index: None,
            needs_title_normalization: None,
        },
    )?;
    let candidate = candidates
        .candidates
        .iter()
        .find(|candidate| candidate.candidate_id == candidate_id)
        .ok_or("work-session-evidence-source-proposals candidate-id was not found in current unresolved session-evidence candidates")?;
    let source_search = run_project_work_session_evidence_source_search(
        ProjectWorkSessionEvidenceSourceSearchOptions {
            source_path: options.source_path,
            query: options.query,
            limit: options.limit,
            max_lines: options.max_lines,
        },
    )?;
    let conn = open_promptvault_database(&database_path)?;
    if !project_work_session_source_path_indexed_for_project(
        &conn,
        &candidate.project,
        &source_search.source_path,
    )? {
        return Err(
            "work-session-evidence-source-proposals source-path is not indexed as a same-project session hint for the candidate"
                .into(),
        );
    }

    Ok(project_work_session_evidence_source_proposals_from_search(
        &database_path,
        candidate,
        source_search,
    ))
}

pub fn run_project_work_session_index(
    options: ProjectWorkSessionIndexOptions,
) -> Result<ProjectWorkSessionIndexResult, Box<dyn std::error::Error>> {
    let until_complete = options.until_complete.unwrap_or(false);
    if matches!(options.limit, Some(0)) {
        return Err("work-session-index limit requires a positive integer".into());
    }
    if matches!(options.batch_files, Some(0)) {
        return Err("work-session-index batch_files requires a positive integer".into());
    }
    if options
        .batch_files
        .is_some_and(|batch_files| batch_files > MAX_PROJECT_WORK_SESSION_INDEX_BATCH_FILES)
    {
        return Err(format!(
            "work-session-index batch_files must be at most {MAX_PROJECT_WORK_SESSION_INDEX_BATCH_FILES}"
        )
        .into());
    }
    if matches!(options.max_batches, Some(0)) {
        return Err("work-session-index max_batches requires a positive integer".into());
    }
    if options.max_batches.is_some() && options.batch_files.is_none() {
        return Err("work-session-index max_batches requires batch_files".into());
    }
    if until_complete && options.batch_files.is_none() {
        return Err("work-session-index until_complete requires batch_files".into());
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err("work-session-index database path requires a non-empty value".into());
    }

    let batch_files = options.batch_files;
    let max_batches =
        project_work_session_index_effective_max_batches(until_complete, options.max_batches);
    if project_work_session_index_needs_long_run_confirmation(max_batches)
        && !options.confirm_long_run.unwrap_or(false)
    {
        return Err(format!(
            "work-session-index long runs require confirm_long_run=true when max_batches exceeds {CONFIRMATION_FREE_PROJECT_WORK_SESSION_INDEX_MAX_BATCHES}"
        )
        .into());
    }

    let generated_at = Utc::now().to_rfc3339();
    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let requested_limit = options.limit.unwrap_or(DEFAULT_PROJECT_WORK_SESSION_LIMIT);
    let reset = options.reset.unwrap_or(false);
    let mut warnings = Vec::new();
    let (prompts, source_states, batches_run) = if let Some(batch_files) = batch_files {
        checkpointed_project_work_session_prompts(
            &database_path,
            batch_files,
            max_batches.unwrap_or(1),
            reset,
            &mut warnings,
        )?
    } else {
        (
            project_work_session_prompts(requested_limit, &mut warnings)?,
            Vec::new(),
            0,
        )
    };
    let persistence = upsert_project_work_session_index(&database_path, &prompts, reset)?;
    let all_sources_completed =
        !source_states.is_empty() && source_states.iter().all(|state| state.completed);
    if until_complete
        && !all_sources_completed
        && max_batches.is_some_and(|max_batches| batches_run >= max_batches)
    {
        warnings.push(
            "work-session-index until_complete stopped at max_batches before all sources completed"
                .to_string(),
        );
    }

    Ok(ProjectWorkSessionIndexResult {
        generated_at,
        database_path: database_path.display().to_string(),
        requested_limit,
        batch_files,
        max_batches,
        until_complete,
        batches_run,
        scanned_prompt_count: prompts.len(),
        sanitized_prompt_count: persistence.sanitized_prompt_count,
        stored_prompt_count: persistence.stored_prompt_count,
        reset,
        all_sources_completed,
        source_states,
        warnings,
    })
}

