pub async fn run_project_work_log_extraction_proposals(
    options: ProjectWorkLogExtractionProposalsOptions,
) -> Result<ProjectWorkLogExtractionProposalsResult, Box<dyn std::error::Error>> {
    if matches!(options.limit, Some(0)) {
        return Err("work-log-extract limit requires a positive integer".into());
    }
    if matches!(options.database_path.as_deref(), Some(path) if path.trim().is_empty()) {
        return Err("database path requires a non-empty value".into());
    }
    let approved_candidate_ids =
        normalized_project_work_log_approved_candidate_ids(&options.approved_candidate_ids)?;
    let database_path = options
        .database_path
        .as_deref()
        .map(PathBuf::from)
        .unwrap_or_else(default_database_path);
    let save = options.save.unwrap_or(false);
    let limit = options
        .limit
        .unwrap_or(DEFAULT_PROJECT_WORK_LOG_CANDIDATE_LIMIT)
        .min(MAX_PROJECT_WORK_LOG_CANDIDATE_LIMIT);
    let approved_review_queue_only = options.approved_review_queue_only.unwrap_or(false);
    let run_started_at = if approved_review_queue_only {
        Some(Utc::now().to_rfc3339())
    } else {
        None
    };
    let candidates = if approved_review_queue_only {
        match run_project_work_log_extraction_candidates_from_approved_review_queue(
            &database_path,
            limit,
        ) {
            Ok(candidates) => candidates,
            Err(err) => {
                if let Some(started_at) = run_started_at.as_deref() {
                    let error_message = err.to_string();
                    let _ = persist_project_work_log_extraction_failure_run(
                        &database_path,
                        ProjectWorkLogExtractionFailureRun {
                            trigger: "approved_review_queue",
                            started_at,
                            provider: "candidate_loader",
                            provider_model: None,
                            provider_runtime: "candidate_loader",
                            used_ai: options.ai.unwrap_or(false),
                            candidate_count: 0,
                            candidate_ids: Vec::new(),
                            warnings: Vec::new(),
                            error_message: &error_message,
                        },
                    );
                }
                return Err(err);
            }
        }
    } else {
        run_project_work_log_extraction_candidates(ProjectWorkLogExtractionCandidatesOptions {
            limit: Some(limit),
        })?
    };
    let failure_candidate_ids = candidates
        .candidates
        .iter()
        .map(|candidate| candidate.candidate_id.clone())
        .collect::<Vec<_>>();
    let approved_review_queue_candidate_ids = if approved_review_queue_only {
        Some(
            candidates
                .candidates
                .iter()
                .map(|candidate| candidate.candidate_id.clone())
                .collect::<HashSet<_>>(),
        )
    } else {
        None
    };
    let mut result = match project_work_log_extraction_proposals_with_env(
        candidates,
        !options.ai.unwrap_or(false),
        load_improve_env(),
    )
    .await
    {
        Ok(result) => result,
        Err(err) => {
            if let Some(started_at) = run_started_at.as_deref() {
                let error_message = err.to_string();
                let _ = persist_project_work_log_extraction_failure_run(
                    &database_path,
                    ProjectWorkLogExtractionFailureRun {
                        trigger: "approved_review_queue",
                        started_at,
                        provider: "provider",
                        provider_model: None,
                        provider_runtime: "provider",
                        used_ai: options.ai.unwrap_or(false),
                        candidate_count: failure_candidate_ids.len(),
                        candidate_ids: failure_candidate_ids,
                        warnings: Vec::new(),
                        error_message: &error_message,
                    },
                );
            }
            return Err(err);
        }
    };
    if save {
        let persistence_approved_candidate_ids = approved_review_queue_candidate_ids
            .as_ref()
            .or(approved_candidate_ids.as_ref());
        result.persistence = match persist_project_work_log_extraction_proposals(
            &database_path,
            &result,
            persistence_approved_candidate_ids,
        ) {
            Ok(persistence) => Some(persistence),
            Err(err) => {
                if let Some(started_at) = run_started_at.as_deref() {
                    let error_message = err.to_string();
                    let _ = persist_project_work_log_extraction_failure_run(
                        &database_path,
                        ProjectWorkLogExtractionFailureRun {
                            trigger: "approved_review_queue",
                            started_at,
                            provider: &result.provider,
                            provider_model: result.provider_model.as_deref(),
                            provider_runtime: &result.provider_runtime,
                            used_ai: result.used_ai,
                            candidate_count: result.candidate_count,
                            candidate_ids: result
                                .proposals
                                .iter()
                                .map(|proposal| proposal.candidate_id.clone())
                                .collect(),
                            warnings: result.warnings.clone(),
                            error_message: &error_message,
                        },
                    );
                }
                return Err(err);
            }
        };
    }
    if let Some(started_at) = run_started_at {
        persist_project_work_log_extraction_run(
            &database_path,
            "approved_review_queue",
            &started_at,
            "completed",
            &result,
            None,
        )?;
    }
    Ok(result)
}

fn normalized_project_work_log_approved_candidate_ids(
    candidate_ids: &Option<Vec<String>>,
) -> Result<Option<HashSet<String>>, Box<dyn std::error::Error>> {
    let Some(candidate_ids) = candidate_ids else {
        return Ok(None);
    };
    let mut normalized = HashSet::new();
    for candidate_id in candidate_ids {
        let trimmed = candidate_id.trim();
        if trimmed.is_empty() {
            return Err("approved candidate ids require non-empty values".into());
        }
        normalized.insert(trimmed.to_string());
    }
    Ok(Some(normalized))
}

fn run_project_work_log_extraction_candidates_from_approved_review_queue(
    database_path: &Path,
    limit: usize,
) -> Result<ProjectWorkLogExtractionCandidatesResult, Box<dyn std::error::Error>> {
    let conn = open_promptvault_database(database_path)?;
    let candidates = read_project_work_log_review_queue_candidates(&conn, "approved", limit)?;
    let root_path = source_specs()
        .into_iter()
        .find(|source| source.id == "project-progress-logs")
        .map(|source| source.root.display().to_string())
        .unwrap_or_else(|| {
            user_home_dir()
                .join("Ai/System/10_Projects")
                .display()
                .to_string()
        });
    let files_seen = candidates
        .iter()
        .map(|candidate| candidate.source_path.clone())
        .collect::<BTreeSet<_>>()
        .len();
    let risk_blocked_candidate_count = candidates
        .iter()
        .filter(|candidate| !candidate.risk_flags.is_empty())
        .count();
    let safe_ai_candidate_count = candidates
        .len()
        .saturating_sub(risk_blocked_candidate_count);
    let (review_queue_state, review_queue_reason) = if candidates.is_empty() {
        ("empty", "no_approved_review_queue_candidates")
    } else {
        ("approved", "approved_review_queue_candidates_ready")
    };
    Ok(ProjectWorkLogExtractionCandidatesResult {
        generated_at: Utc::now().to_rfc3339(),
        root_path,
        files_seen,
        skipped_parsed_file_count: 0,
        skipped_unreadable_file_count: 0,
        skipped_empty_file_count: 0,
        skipped_pointer_file_count: 0,
        review_queue_state: review_queue_state.to_string(),
        review_queue_reason: review_queue_reason.to_string(),
        pending_review_count: candidates.len(),
        safe_ai_candidate_count,
        risk_blocked_candidate_count,
        candidate_count: candidates.len(),
        candidates,
        warnings: Vec::new(),
    })
}

