fn local_improvement(prompt: &str, context: Option<&str>, warnings: Vec<String>) -> ImproveResult {
    let mut revised = String::new();
    let redacted_prompt = redact_sensitive_text(prompt);
    let goal = first_sentence(&redacted_prompt);
    revised.push_str("목표:\n");
    revised.push_str("- ");
    revised.push_str(
        goal.as_deref()
            .unwrap_or("해결하려는 작업을 명확히 수행한다."),
    );
    revised.push_str("\n\n맥락:\n");
    let redacted_context = context
        .filter(|value| !value.trim().is_empty())
        .map(redact_sensitive_text);
    if let Some(context) = redacted_context.as_deref() {
        revised.push_str("- ");
        revised.push_str(context.trim());
        revised.push('\n');
    } else {
        revised.push_str("- 관련 repo/path, 현재 오류, 이미 시도한 방법을 확인한 뒤 진행한다.\n");
    }
    revised.push_str("\n요구사항:\n");
    revised.push_str("- 사용자 원본 파일과 기존 변경을 보존한다.\n");
    revised.push_str("- 필요한 최신 문서나 외부 근거는 출처와 날짜를 남긴다.\n");
    revised.push_str("- 구현은 작은 단위로 진행하고, 변경 파일을 명시한다.\n");
    revised.push_str("- 완료 전 실제 명령으로 빌드/테스트/검증한다.\n");
    revised.push_str("\n완료 보고:\n");
    revised.push_str("- 변경 요약, 검증 결과, 남은 리스크를 짧게 보고한다.");

    ImproveResult {
        provider: "local-rules".to_string(),
        used_ai: false,
        quality_delta: quality_delta(prompt, &revised),
        revised_prompt: revised,
        rationale: vec![
            "목표와 성공 기준을 분리해 에이전트가 산출물을 놓치지 않게 했습니다.".to_string(),
            "권한/보존/검증 조건을 명시해 기존 소스와 비밀정보 리스크를 낮췄습니다.".to_string(),
            "완료 보고 형식을 고정해 결과 검토 비용을 줄였습니다.".to_string(),
        ],
        checklist: prompt_checklist(),
        warnings,
        persistence: None,
    }
}

fn first_sentence(prompt: &str) -> Option<String> {
    prompt
        .split(['.', '?', '!', '\n', '。', '？', '！'])
        .map(str::trim)
        .find(|line| !line.is_empty())
        .map(|line| line.chars().take(180).collect())
}

fn read_secret_env(path: &Path) -> Result<HashMap<String, String>, Box<dyn std::error::Error>> {
    let mut buf = String::new();
    File::open(path)?.read_to_string(&mut buf)?;
    let mut env = HashMap::new();
    for line in buf.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        if let Some((key, value)) = line.split_once('=') {
            env.insert(
                key.trim().to_string(),
                value
                    .trim()
                    .trim_matches('"')
                    .trim_matches('\'')
                    .to_string(),
            );
        }
    }
    Ok(env)
}

fn user_home_dir() -> PathBuf {
    dirs::home_dir()
        .or_else(|| {
            std::env::var_os("HOME")
                .filter(|value| !value.is_empty())
                .map(PathBuf::from)
        })
        .unwrap_or_else(|| std::env::current_dir().unwrap_or_else(|_| PathBuf::from(".")))
}

fn secret_env_candidates_for_home(home: &Path) -> Vec<PathBuf> {
    vec![
        home.join(PROMPTVAULT_SECRET_ENV_RELATIVE_PATH),
        home.join(USER_SECRET_ENV_RELATIVE_PATH),
    ]
}

fn secret_env_candidates() -> Vec<PathBuf> {
    let mut candidates = Vec::new();
    if let Some(path) = std::env::var_os("PROMPTVAULT_SECRET_ENV")
        .filter(|value| !value.is_empty())
        .map(PathBuf::from)
    {
        candidates.push(path);
    }
    candidates.extend(secret_env_candidates_for_home(&user_home_dir()));
    candidates
}

fn load_improve_env() -> HashMap<String, String> {
    let mut env = HashMap::new();
    for path in secret_env_candidates() {
        if let Ok(values) = read_secret_env(&path) {
            env.extend(values);
            break;
        }
    }
    for key in [
        "OPENAI_API_KEY",
        "OPENAI_BASE_URL",
        "OPENAI_RESPONSES_ENDPOINT",
        "OPENAI_MODEL",
        "GLM_API_KEY",
        "GLM_API_KEY_2",
        "GLM_CODING_ENDPOINT",
        "GLM_CODING_MODEL",
        "PATH",
        "CODEX_EXEC_PATH",
        "PROMPTVAULT_CODEX_EXEC_PATH",
        "CODEX_HOME",
        "CODEX_MODEL",
        "CODEX_PROFILE",
        "PROMPTVAULT_AI_HTTP_TIMEOUT_SECONDS",
        "PROMPTVAULT_CODEX_WORK_PROVIDER",
        "PROMPTVAULT_CODEX_TIMEOUT_SECONDS",
    ] {
        if let Ok(value) = std::env::var(key) {
            if !value.trim().is_empty() {
                env.insert(key.to_string(), value);
            }
        }
    }
    env
}

pub fn run_project_work_ai_provider_status() -> ProjectWorkAiProviderStatusResult {
    project_work_ai_provider_status_from_env(load_improve_env())
}

pub async fn run_project_work_ai_provider_health(
) -> Result<ProjectWorkAiProviderHealthResult, String> {
    project_work_ai_provider_health_from_env(load_improve_env()).await
}

fn project_work_ai_provider_status_from_env(
    env: HashMap<String, String>,
) -> ProjectWorkAiProviderStatusResult {
    let openai_configured = openai_api_key_from_env(&env).is_some();
    let glm_configured = glm_api_key_from_env(&env).is_some();
    let codex_exec_path = codex_exec_path_from_env(&env);
    let codex_configured = codex_exec_path.is_some();
    let codex_enabled = codex_work_provider_enabled(&env);
    let codex_usable = codex_configured && codex_enabled;
    let openai_endpoint = normalize_openai_responses_endpoint(
        &env.get("OPENAI_RESPONSES_ENDPOINT")
            .or_else(|| env.get("OPENAI_BASE_URL"))
            .cloned()
            .unwrap_or_else(|| DEFAULT_OPENAI_RESPONSES_ENDPOINT.to_string()),
    );
    let glm_endpoint = normalize_chat_endpoint(
        &env.get("GLM_CODING_ENDPOINT")
            .cloned()
            .unwrap_or_else(|| DEFAULT_GLM_CHAT_ENDPOINT.to_string()),
    );
    let ai_http_timeout_seconds = ai_http_provider_timeout_seconds(&env);
    let external_provider_available = openai_configured || glm_configured;
    let mut warnings = Vec::new();
    if !external_provider_available {
        warnings.push(
            "OpenAI/GLM provider key가 없어 work-management AI 단계는 로컬 fallback으로 실행됩니다."
                .to_string(),
        );
    }
    if codex_usable {
        warnings.push(
            "Codex CLI work-summary/work-log extraction/normalization/session-evidence proposal provider가 opt-in으로 활성화되어 있습니다; durable 저장은 review queue 승인 후에만 가능합니다."
                .to_string(),
        );
    } else if codex_configured {
        warnings.push(
            "Codex CLI route가 감지되었지만 PROMPTVAULT_CODEX_WORK_PROVIDER=1이 아니어서 proposal 생성에는 사용하지 않습니다."
                .to_string(),
        );
    } else {
        warnings.push(
            "Codex SDK/CLI provider route는 아직 사용할 수 없어 work-management proposal 생성에 사용할 수 없습니다."
                .to_string(),
        );
    }

    ProjectWorkAiProviderStatusResult {
        generated_at: Utc::now().to_rfc3339(),
        external_provider_available,
        fallback_provider: "local-fallback-rules".to_string(),
        providers: vec![
            ProjectWorkAiProviderStatusProvider {
                provider: "openai".to_string(),
                provider_runtime: "openai-responses".to_string(),
                configured: openai_configured,
                usable_for_work_management: openai_configured,
                capabilities: provider_work_management_capabilities(openai_configured),
                model: Some(openai_model_from_env(&env)),
                endpoint: Some(openai_endpoint),
                timeout_seconds: Some(ai_http_timeout_seconds),
                notes: if openai_configured {
                    vec![
                        "work-log extraction, normalization, summaries, and session-evidence proposals can attempt OpenAI first.".to_string(),
                        "Configured only means the key and endpoint are present; proposal warnings are the live health evidence.".to_string(),
                    ]
                } else {
                    vec!["OPENAI_API_KEY is not configured.".to_string()]
                },
            },
            ProjectWorkAiProviderStatusProvider {
                provider: "glm".to_string(),
                provider_runtime: "glm-chat-completions".to_string(),
                configured: glm_configured,
                usable_for_work_management: glm_configured,
                capabilities: provider_work_management_capabilities(glm_configured),
                model: Some(glm_model_from_env(&env)),
                endpoint: Some(glm_endpoint),
                timeout_seconds: Some(ai_http_timeout_seconds),
                notes: if glm_configured {
                    vec![
                        "work-log extraction, normalization, summaries, and session-evidence proposals can attempt GLM after OpenAI.".to_string(),
                        "Configured only means the key and endpoint are present; proposal warnings are the live health evidence.".to_string(),
                    ]
                } else {
                    vec!["GLM_API_KEY/GLM_API_KEY_2 is not configured.".to_string()]
                },
            },
            ProjectWorkAiProviderStatusProvider {
                provider: "codex".to_string(),
                provider_runtime: if codex_configured {
                    "codex-cli-exec".to_string()
                } else {
                    "codex-sdk".to_string()
                },
                configured: codex_configured,
                usable_for_work_management: codex_usable,
                capabilities: codex_work_management_capabilities(codex_usable),
                model: non_empty_env_value(&env, "CODEX_MODEL"),
                endpoint: codex_exec_path.clone(),
                timeout_seconds: codex_configured
                    .then(|| codex_work_provider_timeout_seconds(&env)),
                notes: if let Some(path) = codex_exec_path {
                    let mut notes = if codex_usable {
                        vec![format!(
                            "codex exec is opt-in enabled at {path}; work summaries, work-log extraction, normalization, and session-evidence proposals run with read-only sandbox, ephemeral state, and output-schema validation."
                        )]
                    } else {
                        vec![format!(
                            "codex exec was detected at {path}; set PROMPTVAULT_CODEX_WORK_PROVIDER=1 to enable review-gated work summaries, work-log extraction, normalization, and session-evidence proposals."
                        )]
                    };
                    if let Some(profile) = non_empty_env_value(&env, "CODEX_PROFILE") {
                        notes.push(format!("CODEX_PROFILE is set to {profile}."));
                    }
                    if let Some(home) = non_empty_env_value(&env, "CODEX_HOME") {
                        notes.push(format!("CODEX_HOME is configured at {home}."));
                    }
                    notes
                } else {
                    vec![
                        "No Codex SDK/CLI work-management provider is available. Set CODEX_EXEC_PATH or put codex on PATH before wiring proposal generation.".to_string(),
                    ]
                },
            },
        ],
        warnings,
    }
}

async fn project_work_ai_provider_health_from_env(
    env: HashMap<String, String>,
) -> Result<ProjectWorkAiProviderHealthResult, String> {
    let mut providers = Vec::new();
    let openai = probe_openai_project_work_ai_provider_health(&env).await;
    let glm = probe_glm_project_work_ai_provider_health(&env).await;
    let codex = probe_codex_project_work_ai_provider_health(&env).await;
    providers.push(openai);
    providers.push(glm);
    providers.push(codex);

    let live_provider_available = providers.iter().any(|provider| provider.live_ok);
    let mut warnings = Vec::new();
    if !live_provider_available {
        warnings.push(
            "No AI provider passed the live health probe; proposal routes may still fall back locally or require provider repair.".to_string(),
        );
    }
    for provider in providers
        .iter()
        .filter(|provider| provider.configured && !provider.live_ok)
    {
        if let Some(error) = &provider.error {
            warnings.push(format!(
                "{} live health failed: {}",
                provider.provider_runtime, error
            ));
        }
    }

    Ok(ProjectWorkAiProviderHealthResult {
        generated_at: Utc::now().to_rfc3339(),
        live_provider_available,
        providers,
        warnings,
    })
}

async fn probe_openai_project_work_ai_provider_health(
    env: &HashMap<String, String>,
) -> ProjectWorkAiProviderHealthProvider {
    let model = openai_model_from_env(env);
    let endpoint = normalize_openai_responses_endpoint(
        &env.get("OPENAI_RESPONSES_ENDPOINT")
            .or_else(|| env.get("OPENAI_BASE_URL"))
            .cloned()
            .unwrap_or_else(|| DEFAULT_OPENAI_RESPONSES_ENDPOINT.to_string()),
    );
    let timeout_seconds = ai_http_provider_timeout_seconds(env);
    let api_key = match openai_api_key_from_env(env) {
        Some(value) => value,
        None => {
            return project_work_ai_provider_health_row(ProjectWorkAiProviderHealthRow {
                provider: "openai",
                provider_runtime: "openai-responses",
                configured: false,
                probe_attempted: false,
                live_ok: false,
                health_status: "not_configured",
                model: Some(model),
                endpoint: Some(endpoint),
                timeout_seconds: Some(timeout_seconds),
                duration_ms: None,
                http_status: None,
                error: None,
                notes: vec!["OPENAI_API_KEY is not configured; live probe skipped.".to_string()],
            });
        }
    };
    let body = serde_json::json!({
        "model": model,
        "input": [
            {
                "role": "developer",
                "content": [
                    { "type": "input_text", "text": "Return only JSON matching the schema: {\"ok\":true}." }
                ]
            },
            {
                "role": "user",
                "content": [
                    { "type": "input_text", "text": "PromptVault work-management provider health probe. Return {\"ok\":true}." }
                ]
            }
        ],
        "temperature": 0,
        "text": {
            "format": {
                "type": "json_schema",
                "name": "provider_health",
                "strict": true,
                "schema": provider_health_json_schema()
            }
        }
    });
    let started_at = std::time::Instant::now();
    let client = match provider_health_http_client("OpenAI", timeout_seconds) {
        Ok(value) => value,
        Err(err) => {
            return project_work_ai_provider_health_row(ProjectWorkAiProviderHealthRow {
                provider: "openai",
                provider_runtime: "openai-responses",
                configured: true,
                probe_attempted: false,
                live_ok: false,
                health_status: "failed",
                model: Some(model),
                endpoint: Some(endpoint),
                timeout_seconds: Some(timeout_seconds),
                duration_ms: None,
                http_status: None,
                error: Some(err),
                notes: vec!["OpenAI health probe could not build an HTTP client.".to_string()],
            });
        }
    };
    let response = match client
        .post(&endpoint)
        .bearer_auth(api_key)
        .json(&body)
        .send()
        .await
    {
        Ok(value) => value,
        Err(err) => {
            return project_work_ai_provider_health_row(ProjectWorkAiProviderHealthRow {
                provider: "openai",
                provider_runtime: "openai-responses",
                configured: true,
                probe_attempted: true,
                live_ok: false,
                health_status: "failed",
                model: Some(model),
                endpoint: Some(endpoint),
                timeout_seconds: Some(timeout_seconds),
                duration_ms: Some(started_at.elapsed().as_millis() as u64),
                http_status: None,
                error: Some(provider_request_error_detail(&err)),
                notes: vec!["OpenAI live probe transport failed.".to_string()],
            });
        }
    };
    let status = response.status();
    let duration_ms = Some(started_at.elapsed().as_millis() as u64);
    if !status.is_success() {
        return project_work_ai_provider_health_row(ProjectWorkAiProviderHealthRow {
            provider: "openai",
            provider_runtime: "openai-responses",
            configured: true,
            probe_attempted: true,
            live_ok: false,
            health_status: "failed",
            model: Some(model),
            endpoint: Some(endpoint),
            timeout_seconds: Some(timeout_seconds),
            duration_ms,
            http_status: Some(status.as_u16()),
            error: Some(format!("HTTP {status}")),
            notes: vec!["OpenAI live probe returned a non-success HTTP status.".to_string()],
        });
    }
    let parse_result = response
        .json::<Value>()
        .await
        .map_err(|err| format!("OpenAI health response JSON parse failed: {err}"))
        .and_then(|value| {
            openai_response_content(&value)
                .ok_or_else(|| "OpenAI health response did not include output text.".to_string())
        })
        .and_then(|content| {
            provider_health_content_ok(&content)
                .then_some(())
                .ok_or_else(|| "OpenAI health response did not return ok=true.".to_string())
        });
    project_work_ai_provider_health_row(ProjectWorkAiProviderHealthRow {
        provider: "openai",
        provider_runtime: "openai-responses",
        configured: true,
        probe_attempted: true,
        live_ok: parse_result.is_ok(),
        health_status: if parse_result.is_ok() { "ok" } else { "failed" },
        model: Some(model),
        endpoint: Some(endpoint),
        timeout_seconds: Some(timeout_seconds),
        duration_ms,
        http_status: Some(status.as_u16()),
        error: parse_result.err(),
        notes: vec!["OpenAI live probe sent a minimal schema-bound request.".to_string()],
    })
}

