    #[test]
    fn ai_normalization_proposals_require_high_confidence_and_source_evidence() {
        let accepted = normalization_candidate_for_test(
            "work-normalize-PromptVault-accepted".to_string(),
            "2026-06-09: Added supported normalization evidence.".to_string(),
        );
        let low_confidence = normalization_candidate_for_test(
            "work-normalize-PromptVault-low-confidence".to_string(),
            "2026-06-09: Added low-confidence normalization evidence.".to_string(),
        );
        let invented_evidence = normalization_candidate_for_test(
            "work-normalize-PromptVault-invented".to_string(),
            "2026-06-09: Added source-backed normalization evidence.".to_string(),
        );
        let mut candidate_risk = normalization_candidate_for_test(
            "work-normalize-PromptVault-risk".to_string(),
            "2026-06-09: Added risky normalization evidence.".to_string(),
        );
        candidate_risk.risk_flags = vec!["possible_api_key".to_string()];
        let candidates = vec![accepted, low_confidence, invented_evidence, candidate_risk];
        let candidates_result = ProjectWorkLogNormalizationCandidatesResult {
            generated_at: "2026-06-09T00:00:00Z".to_string(),
            database_path: "/tmp/promptvault.sqlite".to_string(),
            total_candidate_count: candidates.len(),
            returned_candidate_count: candidates.len(),
            report_total_items: candidates.len(),
            report_project_count: 1,
            report_date_count: 1,
            candidates: candidates.clone(),
            warnings: Vec::new(),
        };
        let content = serde_json::json!({
            "proposals": [
                {
                    "candidate_id": "work-normalize-PromptVault-accepted",
                    "normalized_title": "Supported normalization evidence",
                    "normalized_status": "current",
                    "normalized_evidence": "2026-06-09: Added supported normalization evidence.",
                    "confidence": PROJECT_WORK_LOG_NORMALIZATION_MIN_ACCEPTED_CONFIDENCE
                },
                {
                    "candidate_id": "work-normalize-PromptVault-low-confidence",
                    "normalized_title": "Low-confidence normalization evidence",
                    "normalized_status": "current",
                    "normalized_evidence": "2026-06-09: Added low-confidence normalization evidence.",
                    "confidence": PROJECT_WORK_LOG_NORMALIZATION_MIN_ACCEPTED_CONFIDENCE - 0.01
                },
                {
                    "candidate_id": "work-normalize-PromptVault-invented",
                    "normalized_title": "Invented normalization evidence",
                    "normalized_status": "current",
                    "normalized_evidence": "2026-06-09: Invented normalization evidence.",
                    "confidence": 0.95
                },
                {
                    "candidate_id": "work-normalize-PromptVault-risk",
                    "normalized_title": "Risky normalization evidence",
                    "normalized_status": "current",
                    "normalized_evidence": "2026-06-09: Added risky normalization evidence.",
                    "confidence": 0.95
                }
            ]
        })
        .to_string();

        let result = project_work_log_normalization_proposals_from_content(
            &candidates_result,
            ProjectWorkLogNormalizationRuntime {
                provider: "glm",
                provider_model: Some("glm-test-model".to_string()),
                provider_runtime: "glm-chat-completions",
                used_ai: true,
            },
            &candidates,
            &content,
            Vec::new(),
        )
        .expect("validated normalization proposals");

        assert_eq!(result.accepted_count, 1);
        assert_eq!(result.rejected_count, 3);
        let proposals_by_id = result
            .proposals
            .iter()
            .map(|proposal| (proposal.candidate_id.as_str(), proposal))
            .collect::<BTreeMap<_, _>>();
        assert!(proposals_by_id["work-normalize-PromptVault-accepted"].accepted);
        assert_eq!(
            proposals_by_id["work-normalize-PromptVault-low-confidence"]
                .rejection_reason
                .as_deref(),
            Some("low_confidence")
        );
        assert_eq!(
            proposals_by_id["work-normalize-PromptVault-invented"]
                .rejection_reason
                .as_deref(),
            Some("evidence_not_in_candidate_evidence")
        );
        assert_eq!(
            proposals_by_id["work-normalize-PromptVault-risk"]
                .rejection_reason
                .as_deref(),
            Some("candidate_has_risk_flags")
        );
    }

    fn glm_normalization_response_for(
        candidates: &[ProjectWorkLogNormalizationCandidate],
    ) -> (u16, Value) {
        let proposals = candidates
            .iter()
            .map(|candidate| {
                serde_json::json!({
                    "candidate_id": candidate.candidate_id,
                    "normalized_title": format!("{} {} normalized", candidate.project, candidate.date),
                    "normalized_status": "current",
                    "normalized_evidence": candidate.evidence,
                    "confidence": 0.91
                })
            })
            .collect::<Vec<_>>();
        let content = serde_json::json!({ "proposals": proposals }).to_string();
        (
            200,
            serde_json::json!({
                "choices": [
                    {
                        "message": {
                            "content": content
                        }
                    }
                ]
            }),
        )
    }

    #[tokio::test]
    async fn project_work_log_normalization_with_env_chunks_glm_requests() {
        let candidates = (0..9)
            .map(|index| {
                normalization_candidate_for_test(
                    format!("work-normalize-PromptVault-{index:012}"),
                    format!("2026-06-09: Normalization candidate {index}."),
                )
            })
            .collect::<Vec<_>>();
        let candidates_result = ProjectWorkLogNormalizationCandidatesResult {
            generated_at: "2026-06-09T00:00:00Z".to_string(),
            database_path: "/tmp/promptvault.sqlite".to_string(),
            total_candidate_count: candidates.len(),
            returned_candidate_count: candidates.len(),
            report_total_items: 9,
            report_project_count: 1,
            report_date_count: 1,
            candidates: candidates.clone(),
            warnings: vec!["candidate warning".to_string()],
        };
        let (endpoint, request_rx) = spawn_json_sequence_server(vec![
            glm_normalization_response_for(&candidates[..8]),
            glm_normalization_response_for(&candidates[8..]),
        ]);
        let mut env = HashMap::new();
        env.insert("GLM_API_KEY".to_string(), "glm-key".to_string());
        env.insert("GLM_CODING_MODEL".to_string(), "glm-test-model".to_string());
        env.insert("GLM_CODING_ENDPOINT".to_string(), endpoint);

        let result =
            project_work_log_normalization_proposals_with_env(candidates_result, false, env)
                .await
                .expect("chunked GLM normalization proposals");
        let first_request = request_rx
            .recv_timeout(std::time::Duration::from_secs(2))
            .expect("capture first GLM normalization request");
        let second_request = request_rx
            .recv_timeout(std::time::Duration::from_secs(2))
            .expect("capture second GLM normalization request");

        assert_eq!(result.provider, "glm");
        assert_eq!(result.provider_model.as_deref(), Some("glm-test-model"));
        assert_eq!(result.returned_proposal_count, 9);
        assert_eq!(result.accepted_count, 9);
        assert_eq!(result.rejected_count, 0);
        assert!(result
            .warnings
            .iter()
            .any(|warning| warning.contains("9개를 2개 chunk")));
        assert!(result.warnings.contains(&"candidate warning".to_string()));
        assert!(first_request.contains("work-normalize-PromptVault-000000000000"));
        assert!(first_request.contains("work-normalize-PromptVault-000000000007"));
        assert!(!first_request.contains("work-normalize-PromptVault-000000000008"));
        assert!(second_request.contains("work-normalize-PromptVault-000000000008"));
        assert!(!second_request.contains("work-normalize-PromptVault-000000000000"));
    }

    #[tokio::test]
    async fn project_work_log_normalization_provider_failure_warning_includes_error_cause() {
        let candidates = vec![normalization_candidate_for_test(
            "work-normalize-PromptVault-request-failure".to_string(),
            "2026-06-09: Normalization provider failure should expose the transport cause."
                .to_string(),
        )];
        let candidates_result = ProjectWorkLogNormalizationCandidatesResult {
            generated_at: "2026-06-09T00:00:00Z".to_string(),
            database_path: "/tmp/promptvault.sqlite".to_string(),
            total_candidate_count: candidates.len(),
            returned_candidate_count: candidates.len(),
            report_total_items: 1,
            report_project_count: 1,
            report_date_count: 1,
            candidates,
            warnings: Vec::new(),
        };
        let mut env = HashMap::new();
        env.insert("GLM_API_KEY".to_string(), "glm-key".to_string());
        env.insert(
            "GLM_CODING_ENDPOINT".to_string(),
            "http://127.0.0.1:9/v4/chat/completions".to_string(),
        );

        let result =
            project_work_log_normalization_proposals_with_env(candidates_result, false, env)
                .await
                .expect("fallback normalization proposals");

        assert_eq!(result.provider, "local-normalization-rules");
        assert_eq!(result.provider_runtime, "local-normalization-rules");
        assert!(!result.used_ai);
        let warning = result
            .warnings
            .iter()
            .find(|warning| warning.contains("GLM work-log normalization 요청 실패"))
            .expect("GLM request failure warning");
        assert!(
            warning.contains("error sending request for url"),
            "{warning}"
        );
        assert!(warning.contains("caused by:"), "{warning}");
    }

